SELECT MAX(end_date) AS latest_end_date
FROM software_life_cycle
WHERE product_id = 1;

SELECT COUNT(revision) AS number_of_revisions
FROM software_products
WHERE product_id = 0;

SELECT c.change_id
FROM changes c
WHERE c.product_id = 1;

SELECT COUNT(DISTINCT product_id) AS ongoing_blueprint_projects
FROM software_life_cycle
WHERE phase = 'Planning' AND status = 'In Progress';
